+        Assert.ThrowsException<KeyNotFoundException>(
+            () => _cart.RemoveItem("MISSING"));
+    }
+
+    [TestMethod]
+    [DataRow(null)]
+    [DataRow("")]
+    public void RemoveItem_InvalidSku_Throws(string? sku)
+    {
+        Assert.ThrowsException<ArgumentException>(
+            () => _cart.RemoveItem(sku!));
+    }
+
+    // ───── CalculateTotal ─────
+
+    [TestMethod]
+    public void CalculateTotal_EmptyCart_ReturnsZero()
+    {
+        Assert.AreEqual(0m, _cart.CalculateTotal());
+    }
+
+    [TestMethod]
+    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
+    {
+        _cart.AddItem("SKU-1", 3, 10.00m);
+        Assert.AreEqual(30.00m, _cart.CalculateTotal());
+    }
+
+    [TestMethod]
+    public void CalculateTotal_MultipleItems_SumsAll()
+    {
+        _cart.AddItem("A", 2, 5.00m);  // 10
+        _cart.AddItem("B", 1, 7.50m);  //  7.50
+
+        Assert.AreEqual(17.50m, _cart.CalculateTotal());
+    }
+
+    [TestMethod]
+    public void CalculateTotal_AfterRemoval_ExcludesRemoved()
+    {
+        _cart.AddItem("A", 1, 10.00m);
+        _cart.AddItem("B", 1, 20.00m);
+        _cart.RemoveItem("A");
+
+        Assert.AreEqual(20.00m, _cart.CalculateTotal());
+    }
+
+    // ───── ApplyCoupon ─────
+
+    [TestMethod]
+    [DataRow("SAVE10", 10)]
+    [DataRow("SAVE20", 20)]
+    [DataRow("HALF",   50)]
+    public void ApplyCoupon_ValidCode_DiscountsTotal(string code, int discountPct)
+    {
+        _cart.AddItem("SKU-1", 1, 100.00m);
+        _cart.ApplyCoupon(code);
+
+        var expected = 100.00m - (100.00m * discountPct / 100m);
+        Assert.AreEqual(expected, _cart.CalculateTotal());
+    }
+
+    [TestMethod]
+    public void ApplyCoupon_ValidCode_SetsAppliedCoupon()
+    {
+        _cart.ApplyCoupon("SAVE10");
+        Assert.AreEqual("SAVE10", _cart.AppliedCoupon);
+    }
+
+    [TestMethod]
+    public void ApplyCoupon_CaseInsensitive()
+    {
+        _cart.AddItem("SKU-1", 1, 100.00m);
+        _cart.ApplyCoupon("save10");
+
+        Assert.AreEqual(90.00m, _cart.CalculateTotal());
+    }
+
+    [TestMethod]
+    public void ApplyCoupon_UnknownCode_Throws()
+    {
+        Assert.ThrowsException<ArgumentException>(
+            () => _cart.ApplyCoupon("BOGUS"));
+    }
+
+    [TestMethod]
+    [DataRow(null)]
+    [DataRow("")]
+    public void ApplyCoupon_InvalidCode_Throws(string? code)
+    {
+        Assert.ThrowsException<ArgumentException>(
+            () => _cart.ApplyCoupon(code!));
+    }
+
+    [TestMethod]
+    public void ApplyCoupon_ReplacePreviousCoupon()
+    {
+        _cart.AddItem("SKU-1", 1, 100.00m);
+        _cart.ApplyCoupon("SAVE10");
+        _cart.ApplyCoupon("SAVE20");
+
+        Assert.AreEqual(80.00m, _cart.CalculateTotal());
+        Assert.AreEqual("SAVE20", _cart.AppliedCoupon);
+    }
+
+    // ───── Integration / edge cases ─────
+
+    [TestMethod]
+    public void FullWorkflow_AddItemsApplyCouponCalculate()
+    {
+        _cart.AddItem("WIDGET", 2, 25.00m);  // 50
+        _cart.AddItem("GADGET", 1, 30.00m);  // 30
+        _cart.ApplyCoupon("HALF");            // 50%
+
+        Assert.AreEqual(40.00m, _cart.CalculateTotal());
+    }
+}
+

